args.ReplacementContent:
"              {/* Seletor de Empresa Ativa */}
              <div className="flex items-center gap-2 bg-slate-50 hover:bg-slate-100 border border-slate-200/60 rounded-xl px-3 py-1.5 transition-all shadow-sm">
                <Building size={14} className="text-slate-500" />
                <select 
                  value={selectedCompanyId}
                  onChange={(e) => setSelectedCompanyId(e.target.value)}
                  className="bg-transparent border-none outline-none font-bold text-xs text-slate-700 p-0 cursor-pointer max-w-[130px] truncate pr-1 focus:ring-0"
                >
                  {companies.map(c => (
                    <option key={c.id} value={c.id} className="bg-white text-slate-700">{c.nomeFantasia}</option>
                  ))}
                </select>
              </div>"
